import React from "react";
import { useState } from "react";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "../../ui/accordion";
import { supabase } from "../../../lib/supabase";
import { LOTTERY_TYPES } from "../../../config/lotteryConfig";
import LotteryNumlotIndexDetailTemplate from "./LotteryNumlotIndexDetailTemplate";
import LotteryNumlotWinningNumbers from "../LotteryNumlotWinningNumbers";
import AdBanner from "../../ads/AdBanner";

import { Badge } from "../../ui/badge";
import { isNew } from "../../../utils/common/format";


export default function LotteryNumlotIndexSummaryTemplate({
  items,
  title,
  lotteryPath,
  lotteryKey,
  hasMore,
  loading,
  onMore,
  showMore,
  fontSize,
}) {
  const [openRounds, setOpenRounds] = useState([]);
  const [detailCache, setDetailCache] = useState({});
  const [loadingRounds, setLoadingRounds] = useState({});

  const config = LOTTERY_TYPES[lotteryKey];

  const handleValueChange = async (values) => {
    // 新しく開いたroundを特定
    const newRound = values.find(
      (v) => !openRounds.includes(v) && !detailCache[v]
    );
    setOpenRounds(values);

    if (!newRound) return;

    // ローディング状態ON
    setLoadingRounds((prev) => ({ ...prev, [newRound]: true }));

    try {
      const { data, error } = await supabase
        .schema("chatorahack")
        .rpc("get_lottery_numlot_detail", {
          p_lottery_key: lotteryKey,
          p_round: parseInt(newRound, 10),
        });

      if (error) throw error;
      const row = data[0];
      if (!row) throw new Error("データなし");

      setDetailCache((prev) => ({
        ...prev,
        [newRound]: { ...row, lotteryKey },
      }));
    } catch (err) {
      // console.error("Fetch Error Detail:", err);
      setDetailCache((prev) => ({ ...prev, [newRound]: null }));
    } finally {
      setLoadingRounds((prev) => ({ ...prev, [newRound]: false }));
    }
  };

  return (
    <div className="" title={title}>
      <Accordion
        type="multiple"
        value={openRounds}
        onValueChange={handleValueChange}
        className="grid gap-4"
      >
        {items.map((item, index) => (
          <React.Fragment key={item.uuid}>
            <AccordionItem
              key={item.uuid}
              value={String(item.round)}
              className="relative border border-primary-500 rounded-lg bg-base-50 w-full"
            >
              <div className="absolute -top-2 left-2 flex gap-1">
                {isNew(item.draw_date) && <Badge variant="destructive">NEW</Badge>}
                {item.carryover > 0 && <Badge variant="gold">CO</Badge>}
              </div>
              <AccordionTrigger className="flex flex-col md:flex-row items-center px-4 py-4 gap-2 relative hover:no-underline [&>svg]:ml-auto [&>svg]:shrink-0 [&>svg]:absolute [&>svg]:right-2 [&>svg]:md:relative [&>svg]:text-primary-500">
                {/* 回号・日付 */}
                <div className="flex flex-row md:flex-col items-start items-baseline w-full md:w-auto gap-2 md:gap-0">
                  <span className="text-xs text-primary-500 font-bold">第 {item.round} 回</span>
                  <span className="text-sm text-primary-500">{item.draw_date}</span>
                </div>

                {/* 当選番号 */}
                <div className="flex-1 flex justify-center w-full md:w-auto ">
                  <LotteryNumlotWinningNumbers
                    mainNumber={item.main_number}
                    bonusNumber={item.bonus_number}
                    config={config}
                    size="sm"
                    fontSize={fontSize}
                  />
                </div>
              </AccordionTrigger>

              <AccordionContent className="px-4 pb-4">
                <LotteryNumlotIndexDetailTemplate
                  data={detailCache[String(item.round)]}
                  config={config}
                  loading={loadingRounds[String(item.round)] ?? false}
                />
              </AccordionContent>
            </AccordionItem>
            {(index + 1) % 10 === 0 && (
              <AdBanner key={`ad-${index}`} />
            )}
          </React.Fragment>
        ))}
      </Accordion>

      {showMore && hasMore && (
        <div className="my-16 mx-auto max-w-sm">
          <button
            onClick={onMore}
            disabled={loading}
            className="w-full block py-2 text-primary-500 border border-primary-500 rounded-xl font-bold bg-base-50 hover:bg-primary-500 hover:text-base-50 transition-colors text-center"
          >
            {loading ? "読み込み中..." : "さらに表示"}
          </button>
        </div>
      )}
    </div>
  );
}