// src/components/common/SiteVersion.jsx
import { CHANGELOG_CONFIG } from "../../data/changeLog";
import { cn } from "../../lib/utils";

export default function SiteVersion({ className = "" }) {
  const latest = CHANGELOG_CONFIG[0];
  if (!latest) return null;
  return (
    <span className={cn("text-xs text-primary-500/50", className)}>
      v{latest.version}
    </span>
  );
}

