import { LOTTERY_TYPES } from "../../../config/lotteryConfig";
import { formatAmount, formatCount, formatDate, formatRound } from "../../../utils/common/format";
import LotteryNumlotWinningNumbers from "../LotteryNumlotWinningNumbers";
import AdRectangle from "../../ads/AdRectangle";
import PageMeta from "../../common/PageMeta";
import NoData from "../../common/NoData";
import { useEffect, useRef, useState } from "react";

const MIN_LOADING_MS = 500;

export default function LotteryNumlotDetailTemplate({
  data,
  config,
  loading,
}) {
  const [showLoading, setShowLoading] = useState(loading);
  const loadingStartedAt = useRef(Date.now());
  useEffect(() => {
    let timer;

    if (loading) {
      loadingStartedAt.current = Date.now();
      setShowLoading(true);
    } else {
      const elapsed = Date.now() - loadingStartedAt.current;
      const remaining = Math.max(0, MIN_LOADING_MS - elapsed);

      timer = setTimeout(() => {
        setShowLoading(false);
      }, remaining);
    }

    return () => clearTimeout(timer);
  }, [loading]);

  if (showLoading) {
    return (
      <div className="container max-w-[768px] mx-auto">
        <div className="py-4 space-y-2 animate-pulse">
          <div className="h-4 bg-primary-500/30 rounded w-3/4" />
          <div className="h-4 bg-primary-500/20 rounded w-1/2" />
          <div className="h-4 bg-primary-500/10 rounded w-2/3" />
        </div>
      </div>
    );
  }

  if (!data) {
    return (
      <>
        <PageMeta
          title="データが見つかりません"
          description="該当するデータが見つかりませんでした。"
          noindex
        />
        <NoData />
      </>
    );
  }

  return (
    <>
      <PageMeta
        title={`${formatRound(data.round)} | ${config?.label}`}
        description={`${config?.label} ${formatRound(data.round)}（${formatDate(data.draw_date)}）の当選番号・［ 払戻金 ］情報。`}
        path={`${config?.path}detail?round=${data.round}`}
        breadcrumbs={[
          { name: "TOP", path: "/" },
          { name: config?.label, path: config?.path },
          { name: formatRound(data.round), path: `${config?.path}detail?round=${data.round}` },
        ]}
      />
      <div className="container mx-auto p-4 md:p-8 bg-base-50 rounded-xl">
        <div className="flex justify-between items-center flex-wrap mb-16 border-b border-b-2 border-primary-500 pb-2">
          <h1 className="text-2xl font-bold text-primary-500">
            {config?.label} {formatRound(data.round)}
          </h1>
          {/* 抽選日 */}
          <div className="text-primary-500 font-bold ml-auto">
            <dl className="grid grid-cols-[auto_auto] gap-x-2 justify-end text-sm">
              <dt>抽選日</dt>
              <dd className="">{formatDate(data.draw_date)}</dd>
            </dl>
          </div>
        </div>

        <div className="">
          {/* 当選番号セクション */}
          <div className="mb-16 text-center">
            <LotteryNumlotWinningNumbers
              mainNumber={data.main_number}
              bonusNumber={data.bonus_number}
              config={config}
              size="lg"
            />
          </div>

          {/* 払戻テーブル */}
          <div className="overflow-x-auto">
            <table className="w-full text-[10px] sm:text-xs md:text-sm border border-primary-500 whitespace-nowrap">
              <thead>
                <tr className="text-primary-500 border-b border-primary-500 text-left"
                  style={{
                    backgroundColor: '#fdfbf7',
                    backgroundImage: 'radial-gradient(circle, rgba(227,0,127,0.2) 1px, transparent 1px), radial-gradient(circle, rgba(227,0,127,0.2) 1px, transparent 1px)',
                    backgroundPosition: '2px 0, 6px 2px',
                    backgroundSize: '8px 4px',
                  }}
                >
                  <th className="px-2 md:px-4 py-2 font-bold">［ 等級 ］</th>
                  <th className="px-2 md:px-4 py-2 font-bold text-right">［ 当選口数 ］</th>
                  <th className="px-2 md:px-4 py-2 font-bold text-right">［ 払戻金 ］</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-dashed divide-primary-500">
                {(data.payouts || []).map((payout, i) => (
                  <tr key={i}>
                    <td className="px-2 md:px-4 py-2 text-primary-500">
                      {payout.name ? payout.name : `［ ${payout.grade}等 ］`}
                    </td>
                    <td className="px-2 md:px-4 py-2 text-right font-bold text-primary-500">{formatCount(payout.winners)}</td>
                    <td className="px-2 md:px-4 py-2 text-right font-bold text-primary-500">
                      {formatAmount(payout.amount)}
                    </td>
                  </tr>
                ))}
                {data.carryover != null && data.carryover > 0 && (
                  <tr>
                    <td className="px-2 md:px-4 py-2 text-primary-500">［ キャリーオーバー ］</td>
                    <td colSpan={2} className="px-2 md:px-4 py-2 text-right font-bold text-primary-500">
                      {formatAmount(data.carryover)}
                    </td>
                  </tr>
                )}
              </tbody>
              <tfoot>
                {data.sales_amount != null && (
                  <tr className="border-t border-primary-500">
                    <th className="px-2 md:px-4 py-2 font-normal text-primary-500 text-left">［ 販売実績 ］</th>
                    <td colSpan={2} className="px-2 md:px-4 py-2 text-right font-bold text-primary-500">
                      {formatAmount(data.sales_amount)}
                    </td>
                  </tr>
                )}
              </tfoot>
            </table>
            <p className="mt-2 text-[10px] text-primary-500/50 text-right">
              ※データの正確性は保証しません。当選確認は必ず公式サイトでご確認ください。
            </p>
          </div>
        </div>

        {/* ページネーションボタン */}
        <div className="mt-16 flex flex-wrap justify-between gap-2 text-sm">
          <button
            disabled={data.is_latest}
            onClick={() => {
              const params = new URLSearchParams(window.location.search);
              params.set("round", Number(data.round) + 1);
              window.location.search = params.toString();
            }}
            className="order-1 px-4 py-2 hover:bg-primary-500 text-primary-500 hover:text-base-50 border border-primary-500 rounded-lg transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
          >
            {config?.label} 第{Number(data.round) + 1}回
          </button>

          <button
            onClick={() => {
              const path = LOTTERY_TYPES[data.lotteryKey]?.path || "/";
              window.location.href = path;
            }}
            className="order-3 sm:order-2 w-full sm:w-auto px-4 py-2 bg-primary-500 hover:bg-base-50 text-base-50 hover:text-primary-500 border border-primary-500 rounded-lg transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
          >
            {config?.label} TOP
          </button>

          <button
            disabled={Number(data.round) <= 1}
            onClick={() => {
              const params = new URLSearchParams(window.location.search);
              params.set("round", Number(data.round) - 1);
              window.location.search = params.toString();
            }}
            className="order-2 sm:order-3 px-4 py-2 hover:bg-primary-500 text-primary-500 hover:text-base-50 border border-primary-500 rounded-lg transition-colors disabled:opacity-30 disabled:cursor-not-allowed ml-auto md:ml-0"
          >
            {config?.label} 第{Number(data.round) - 1}回
          </button>
        </div>
      </div>
      <div className="container mx-auto mt-8 mb-8 flex justify-center flex-wrap gap-4">
        <AdRectangle />
        <AdRectangle />
      </div>
    </>
  );
}