import PageMeta from "../../components/common/PageMeta";
import { NEWS } from "../../data/news";

export default function News() {
  return (
    <>
      <PageMeta
        title="お知らせ"
        description="ChatoraHack Lotteryからのお知らせです。"
        path="/news"
        breadcrumbs={[
          { name: "TOP", path: "/" },
          { name: "お知らせ", path: "/news" },
        ]}
      />
      
      <div className="mx-auto mb-8">
        
        <div className="flex justify-between items-center flex-wrap mb-8 border-b border-b-2 border-primary-500 pb-2">
          <h1 className="text-2xl font-bold text-primary-500">
            お知らせ
          </h1>
        </div>

        <div className="p-8 bg-base-50 rounded-3xl">
          <section className="mb-8">
            <ul className="divide-y divide-primary-500">
              {NEWS.map((item) => (
                <li key={item.date} className="py-2 flex gap-4 items-baseline leading-relaxed">
                  <span className="text-base text-primary-500 shrink-0">
                    {item.date}
                  </span>
                  <span className="text-base text-primary-500">{item.title}</span>
                </li>
              ))}
            </ul>
          </section>
        </div>
      </div>
    </>
  );
}
