import { useState, useEffect } from "react";
import { supabase } from "../../../lib/supabase";
import { LOTTERY_TYPES } from "../../../config/lotteryConfig";
import NProgress from 'nprogress'
import 'nprogress/nprogress.css'

export default function LotteryNumlotDetailContainer({ lotteryKey, Template }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // 1. useEffectの中でconfigを特定する（より安全な方法）
    const config = LOTTERY_TYPES[lotteryKey];
    const params = new URLSearchParams(window.location.search);
    const round = params.get("round");

    if (!round || !config) {
      setLoading(false);
      return;
    }

    const fetchDetail = async () => {
      NProgress.start();
      setLoading(true);
      try {

        const { data: maxRoundData } = await supabase
          .schema('chatorahack')
          .from(config.tableName)
          .select('round')
          .order('round', { ascending: false })
          .limit(1)
          .single();
          
        // const { data: result, error } = await supabase
        //   .schema('chatorahack')
        //   .from(config.tableName)
        //   .select('*')
        //   .eq('round', parseInt(round, 10))
        //   .single();

        const { data: result, error } = await supabase
          .schema('chatorahack')
          .rpc('get_lottery_numlot_detail', {
            p_lottery_key: lotteryKey,
            p_round: parseInt(round, 10)
        });

        if (error) throw error;
        const row = result[0];  // 先頭の1件を取得
        if (!row) throw new Error("データなし");
        setData({
          ...row,
          is_latest: row.round === maxRoundData?.round,
          lotteryKey: lotteryKey,  // typeの代わりにlotteryKeyを使う
        });
      } catch (err) {
        // console.error("Fetch Error Detail:", err);
        setData(null); // 失敗時はデータをクリア
      } finally {
        setLoading(false);
        NProgress.done();
      }
    };

    fetchDetail();
    
    // lotteryKeyが変わったときに必ず再実行させる
  }, [lotteryKey]); 

  // configをTemplateに渡すために外でも定義
  const currentConfig = LOTTERY_TYPES[lotteryKey];

  return <Template data={data} config={currentConfig} loading={loading} />;
}